// Luhn algorithm
function luhnComplete(partial) {
  const digits = partial.split('').map(Number);
  // Calculate check digit
  let sum = 0;
  let double = true;
  for (let i = digits.length - 1; i >= 0; i--) {
    let d = digits[i];
    if (double) { d *= 2; if (d > 9) d -= 9; }
    sum += d;
    double = !double;
  }
  const check = (10 - (sum % 10)) % 10;
  return partial + check;
}

function randDigits(n) {
  return Array.from({length: n}, () => Math.floor(Math.random() * 10)).join('');
}

const NETWORKS = {
  visa:       { prefix: ['4'], len: 16 },
  mastercard: { prefix: ['51','52','53','54','55'], len: 16 },
  amex:       { prefix: ['34','37'], len: 15 },
  discover:   { prefix: ['6011','65'], len: 16 },
};

const network = options.network ?? 'all';
const count = Math.max(1, Math.min(10, Number(options.count ?? 3)));
const targets = network === 'all' ? Object.keys(NETWORKS) : [network];

const lines = ['TEST CARD NUMBERS — FOR TESTING ONLY — NOT REAL CARDS', ''];
for (const net of targets) {
  const cfg = NETWORKS[net];
  if (!cfg) continue;
  lines.push(net.toUpperCase() + ':');
  for (let i = 0; i < count; i++) {
    const prefix = cfg.prefix[Math.floor(Math.random() * cfg.prefix.length)];
    const partial = prefix + randDigits(cfg.len - prefix.length - 1);
    const card = luhnComplete(partial);
    const expM = String(Math.floor(Math.random()*12)+1).padStart(2,'0');
    const expY = String(new Date().getFullYear() + 1 + Math.floor(Math.random()*4)).slice(-2);
    const cvv = randDigits(net === 'amex' ? 4 : 3);
    lines.push(`  ${card}  Exp: ${expM}/${expY}  CVV: ${cvv}`);
  }
  lines.push('');
}
return { output: lines.join('\n').trimEnd(), outputLanguage: 'text' };
